import heapq

def dijkstra(graph, start):
    dist = {start: 0}
    pq = [(0, start)]
    while pq:
        d, n = heapq.heappop(pq)
        if d > dist.get(n, float('inf')):
            continue
        for nbr, w in graph.get(n, []):
            nd = d + w
            if nd < dist.get(nbr, float('inf')):
                dist[nbr] = nd
                heapq.heappush(pq, (nd, nbr))
    return dist

