    if cols_a != rows_b:
        raise ValueError('incompatible shapes')
    out = [[0] * cols_b for _ in range(rows_a)]
    for i in range(rows_a):
        for j in range(cols_b):
            for k in range(cols_a):
                out[i][j] += a[i][k] * b[k][j]
    return out

